  1→/**
  2→ * Agent Activator
  3→ *
  4→ * POST endpoint handler called by SurrealDB DEFINE EVENT webhook when
  5→ * observations are created. Uses LLM classification to determine which
  6→ * registered agent types should be activated for a given observation,
  7→ * then starts new agent sessions for matched agents.
  8→ *
  9→ * Observations targeting entities with active agent sessions are skipped —
 10→ * the LLM proxy handles enriching those sessions via its own vector search.
 11→ *
 12→ * LLM classification over KNN because the question is "which agents can
 13→ * ACT on this observation?" — a judgment problem, not a proximity problem.
 14→ * See ADR-061.
 15→ *
 16→ * Step: 03-02 (Graph-Reactive Coordination)
 17→ */
 18→import { RecordId, type Surreal } from "surrealdb";
 19→import { generateObject, type LanguageModel } from "ai";
 20→import { z } from "zod";
 21→import { log } from "../telemetry/logger";
 22→import type { LoopDampener, DampenerEvent } from "./loop-dampener";
 23→
 24→// ---------------------------------------------------------------------------
 25→// Domain Types
 26→// ---------------------------------------------------------------------------
 27→
 28→/** Webhook payload from SurrealDB DEFINE EVENT on observation CREATE. */
 29→export type ObservationWebhookPayload = {
 30→  observation_id: string;
 31→  workspace: string;
 32→  text: string;
 33→  severity: string;
 34→  source_agent: string;
 35→};
 36→
 37→/** A registered agent type with its description. */
 38→export type RegisteredAgent = {
 39→  agentId: string;
 40→  agentType: string;
 41→  description: string;
 42→};
 43→
 44→/** An agent matched by LLM classification for activation. */
 45→export type AgentActivation = {
 46→  agentId: string;
 47→  agentType: string;
 48→  workspaceId: string;
 49→  reason: string;
 50→  observationId: string;
 51→  observationText: string;
 52→};
 53→
 54→/** Callback invoked when the activator decides to start a new agent. */
 55→export type OnAgentActivation = (activation: AgentActivation) => void;
 56→
 57→/** Inflight tracker for background async work. */
 58→export type InflightTracker = {
 59→  track: (promise: Promise<unknown>) => void;
 60→};
 61→
 62→/** Dependencies injected into the agent activator. */
 63→export type AgentActivatorDeps = {
 64→  surreal: Surreal;
 65→  loopDampener: LoopDampener;
 66→  inflight: InflightTracker;
 67→  classifierModel: LanguageModel;
 68→  onAgentActivation: OnAgentActivation;
 69→  /** Shared secret for webhook authentication. If undefined, all requests are allowed (dev mode). */
 70→  internalWebhookSecret?: string;
 71→};
 72→
 73→// ---------------------------------------------------------------------------
 74→// Pure Functions
 75→// ---------------------------------------------------------------------------
 76→
 77→/**
 78→ * Parses and validates the webhook payload from SurrealDB DEFINE EVENT.
 79→ * Returns undefined if the payload is invalid.
 80→ */
 81→export function parseWebhookPayload(
 82→  body: unknown,
 83→): ObservationWebhookPayload | undefined {
 84→  if (!body || typeof body !== "object") return undefined;
 85→  const b = body as Record<string, unknown>;
 86→
 87→  const observation_id = b.observation_id;
 88→  const workspace = b.workspace;
 89→  const text = b.text;
 90→  const severity = b.severity;
 91→  const source_agent = b.source_agent;
 92→
 93→  if (
 94→    typeof observation_id !== "string" ||
 95→    typeof text !== "string" ||
 96→    typeof severity !== "string" ||
 97→    typeof source_agent !== "string" ||
 98→    !workspace
 99→  ) {
100→    return undefined;
101→  }
102→
103→  // workspace may be a string "workspace:id" or just the id
104→  let workspaceId: string;
105→  if (typeof workspace === "string") {
106→    workspaceId = workspace.includes(":") ? workspace.split(":").slice(1).join(":") : workspace;
107→  } else if (workspace instanceof RecordId) {
108→    workspaceId = workspace.id as string;
109→  } else {
110→    return undefined;
111→  }
112→
113→  return {
114→    observation_id: typeof observation_id === "string" && observation_id.includes(":")
115→      ? observation_id.split(":").slice(1).join(":")
116→      : observation_id,
117→    workspace: workspaceId,
118→    text,
119→    severity,
120→    source_agent,
121→  };
122→}
123→
124→/**
125→ * Validates the webhook request's Authorization header against the shared secret.
126→ * Returns true if the secret is not configured (dev mode) or if the header matches.
127→ */
128→export function validateWebhookSecret(
129→  authHeader: string | undefined,
130→  secret: string | undefined,
131→): boolean {
132→  if (!secret) return true; // dev mode: no secret configured, allow all
133→  if (!authHeader) return false;
134→  return authHeader === `Bearer ${secret}`;
135→}
136→
137→/**
138→ * Builds a dampener event key from webhook payload fields.
139→ */
140→export function buildDampenerEvent(
141→  workspaceId: string,
142→  entityId: string,
143→  sourceAgent: string,
144→): DampenerEvent {
145→  return { workspaceId, entityId, sourceAgent };
146→}
147→
148→/**
149→ * Builds the LLM classification prompt from observation + agent descriptions.
150→ */
151→export function buildClassificationPrompt(
152→  observation: { text: string; severity: string },
153→  agents: ReadonlyArray<RegisteredAgent>,
154→): string {
155→  const agentList = agents
156→    .map((a) => `- Agent "${a.agentId}" (type: ${a.agentType}): ${a.description}`)
157→    .join("\n");
158→
159→  return `You are an agent activator. Given an observation from a knowledge graph, determine which registered agents should be started to handle it.
160→
161→## Observation
162→Severity: ${observation.severity}
163→Text: ${observation.text}
164→
165→## Registered Agents
166→${agentList}
167→
168→## Instructions
169→- Select agents that can TAKE ACTION on this observation (not just agents with related keywords)
170→- Consider the severity: conflict observations need immediate action, info observations may not need any agent
171→- If no agent is relevant, return an empty list
172→- For each selected agent, explain briefly why it should be activated`;
173→}
174→
175→// ---------------------------------------------------------------------------
176→// LLM Classification Schema
177→// ---------------------------------------------------------------------------
178→
179→const classificationSchema = z.object({
180→  activations: z.array(z.object({
181→    agent_id: z.string().describe("The agent ID to activate"),
182→    reason: z.string().describe("Brief explanation of why this agent should handle the observation"),
183→  })),
184→});
185→
186→// ---------------------------------------------------------------------------
187→// DB Queries (Side-Effect Boundary)
188→// ---------------------------------------------------------------------------
189→
190→/**
191→ * Loads all registered agents for a workspace (via identity membership).
192→ */
193→async function loadWorkspaceAgents(
194→  surreal: Surreal,
195→  workspaceId: string,
196→): Promise<RegisteredAgent[]> {
197→  const workspaceRecord = new RecordId("workspace", workspaceId);
198→
199→  // Two-step: get workspace member identities, then find their agents
200→  const result = await surreal.query<[unknown, Array<{
201→    id: RecordId;
202→    agent_type: string;
203→    description: string;
204→  }>]>(
205→    `LET $members = (SELECT VALUE in FROM member_of WHERE out = $ws);
206→     SELECT id, agent_type, description FROM agent
207→     WHERE managed_by IN $members
208→     AND description IS NOT NONE;`,
209→    { ws: workspaceRecord },
210→  );
211→
212→  return (result[1] ?? []).map((a) => ({
213→    agentId: a.id.id as string,
214→    agentType: a.agent_type,
215→    description: a.description,
216→  }));
217→}
218→
219→/**
220→ * Resolves the target entity for an observation by querying the observes edge.
221→ */
222→async function resolveObservationTarget(
223→  surreal: Surreal,
224→  observationId: string,
225→): Promise<{ table: string; id: string } | undefined> {
226→  const obsRecord = new RecordId("observation", observationId);
227→  const result = await surreal.query<[Array<{ out: RecordId }>]>(
228→    `SELECT out FROM observes WHERE in = $obs LIMIT 1;`,
229→    { obs: obsRecord },
230→  );
231→  const edge = result[0]?.[0];
232→  if (edge?.out instanceof RecordId) {
233→    return { table: edge.out.table.name, id: edge.out.id as string };
234→  }
235→  return undefined;
236→}
237→
238→/**
239→ * Checks whether the observation's target entity already has an active
240→ * agent session. If so, the proxy handles context enrichment.
241→ */
242→async function hasActiveCoverage(
243→  surreal: Surreal,
244→  target: { table: string; id: string },
245→  workspaceId: string,
246→): Promise<boolean> {
247→  const workspaceRecord = new RecordId("workspace", workspaceId);
248→  const taskRecord = new RecordId(target.table, target.id);
249→
250→  const result = await surreal.query<[Array<{ count: number }>]>(
251→    `SELECT count() AS count FROM agent_session
252→     WHERE task_id = $task AND workspace = $ws AND orchestrator_status = "active"
253→     LIMIT 1;`,
254→    { task: taskRecord, ws: workspaceRecord },
255→  );
256→
257→  const count = result[0]?.[0]?.count ?? 0;
258→  return count > 0;
259→}
260→
261→/**
262→ * Creates a new agent session for a matched agent, marking it as "spawning".
263→ */
264→async function createActivatedSession(
265→  surreal: Surreal,
266→  match: { agentType: string; workspaceId: string; observationId: string },
267→): Promise<string> {
268→  const sessionId = `sess-${crypto.randomUUID()}`;
269→  const sessionRecord = new RecordId("agent_session", sessionId);
270→  const workspaceRecord = new RecordId("workspace", match.workspaceId);
271→  const observationRecord = new RecordId("observation", match.observationId);
272→
273→  await surreal.query(`CREATE $sess CONTENT $content;`, {
274→    sess: sessionRecord,
275→    content: {
276→      agent: match.agentType,
277→      started_at: new Date(),
278→      workspace: workspaceRecord,
279→      orchestrator_status: "spawning",
280→      source: "activator",
281→      triggered_by: observationRecord,
282→      created_at: new Date(),
283→    },
284→  });
285→
286→  return sessionId;
287→}
288→
289→/**
290→ * Creates a provisional decision recording the activator's routing choice.
291→ * Only for conflict/warning severity observations. Links to the observation
292→ * via relates_to edge. Appears in the governance feed for human oversight.
293→ */
294→async function createActivationDecision(
295→  surreal: Surreal,
296→  workspaceId: string,
297→  observationId: string,
298→  observationText: string,
299→  severity: string,
300→  activatedAgents: Array<{ agentType: string; reason: string }>,
301→): Promise<string> {
302→  const decisionId = `dec-act-${crypto.randomUUID()}`;
303→  const decisionRecord = new RecordId("decision", decisionId);
304→  const workspaceRecord = new RecordId("workspace", workspaceId);
305→  const observationRecord = new RecordId("observation", observationId);
306→
307→  const agentSummary = activatedAgents.length > 0
308→    ? activatedAgents.map((a) => `${a.agentType}: ${a.reason}`).join("; ")
309→    : "No agents matched — observation logged for future context";
310→
311→  const summary = activatedAgents.length > 0
312→    ? `Activated ${activatedAgents.length} agent(s) for ${severity} observation`
313→    : `No agents activated for ${severity} observation`;
314→
315→  await surreal.query(`CREATE $dec CONTENT $content;`, {
316→    dec: decisionRecord,
317→    content: {
318→      summary,
319→      rationale: `Observation: "${observationText}"\n\nRouting: ${agentSummary}`,
320→      status: "provisional",
321→      inferred_by: "agent_activator",
322→      category: "operations",
323→      workspace: workspaceRecord,
324→      based_on: [observationRecord],
325→      created_at: new Date(),
326→      updated_at: new Date(),
327→    },
328→  });
329→
330→  // Link decision to observation
331→  await surreal.query(
332→    `RELATE $dec->relates_to->$obs SET created_at = time::now();`,
333→    { dec: decisionRecord, obs: observationRecord },
334→  );
335→
336→  return decisionId;
337→}
338→
339→/**
340→ * Creates a governance observation when the LLM hallucinates unknown agent IDs.
341→ * Makes the hallucination visible in the feed for human oversight.
342→ */
343→async function createHallucinationObservation(
344→  surreal: Surreal,
345→  workspaceId: string,
346→  observationId: string,
347→  hallucinatedIds: string[],
348→): Promise<void> {
349→  const metaId = `meta-halluc-${crypto.randomUUID()}`;
350→  const metaRecord = new RecordId("observation", metaId);
351→  const workspaceRecord = new RecordId("workspace", workspaceId);
352→  const sourceObsRecord = new RecordId("observation", observationId);
353→
354→  await surreal.query(`CREATE $obs CONTENT $content;`, {
355→    obs: metaRecord,
356→    content: {
357→      text: `Agent activator LLM hallucinated ${hallucinatedIds.length} agent ID(s) for observation ${observationId}: ${hallucinatedIds.join(", ")}`,
358→      severity: "info",
359→      status: "open",
360→      category: "engineering",
361→      source_agent: "agent_activator",
362→      workspace: workspaceRecord,
363→      created_at: new Date(),
364→      updated_at: new Date(),
365→    },
366→  });
367→
368→  // Link to the source observation
369→  await surreal.query(
370→    `RELATE $meta->observes->$obs SET created_at = time::now();`,
371→    { meta: metaRecord, obs: sourceObsRecord },
372→  );
373→}
374→
375→/**
376→ * Creates a meta-observation when the loop dampener activates.
377→ */
378→async function createDampeningMetaObservation(
379→  surreal: Surreal,
380→  workspaceId: string,
381→  entityId: string,
382→  sourceAgent: string,
383→): Promise<void> {
384→  const metaId = `meta-${crypto.randomUUID()}`;
385→  const metaRecord = new RecordId("observation", metaId);
386→  const workspaceRecord = new RecordId("workspace", workspaceId);
387→
388→  await surreal.query(`CREATE $obs CONTENT $content;`, {
389→    obs: metaRecord,
390→    content: {
391→      text: `Loop dampener activated: rapid-fire observations from ${sourceAgent} targeting ${entityId} have been dampened to prevent cascading agent invocations`,
392→      severity: "info",
393→      status: "open",
394→      category: "engineering",
395→      source_agent: "agent_activator",
396→      workspace: workspaceRecord,
397→      created_at: new Date(),
398→      updated_at: new Date(),
399→    },
400→  });
401→}
402→
403→// ---------------------------------------------------------------------------
404→// Agent Activator Handler (Side-Effect Shell)
405→// ---------------------------------------------------------------------------
406→
407→/**
408→ * Creates the agent activator POST endpoint handler.
409→ *
410→ * Called by SurrealDB DEFINE EVENT webhook on observation CREATE.
411→ * Parses the webhook payload, checks loop dampener, checks active coverage,
412→ * uses LLM to classify which agents should handle the observation,
413→ * starts new agent sessions for matched agents.
414→ */
415→export function createAgentActivatorHandler(deps: AgentActivatorDeps) {
416→  const { surreal, loopDampener, inflight, classifierModel, onAgentActivation, internalWebhookSecret } = deps;
417→
418→  return async function handleObservationWebhook(request: Request): Promise<Response> {
419→    // Validate shared secret if configured
420→    const authHeader = request.headers.get("authorization") ?? undefined;
421→    if (!validateWebhookSecret(authHeader, internalWebhookSecret)) {
422→      return new Response("unauthorized", { status: 401 });
423→    }
424→
425→    const body = await request.json().catch(() => undefined);
426→    const payload = parseWebhookPayload(body);
427→
428→    if (!payload) {
429→      return new Response("invalid payload", { status: 200 });
430→    }
431→
432→    // Process async — return 200 immediately (same pattern as observer-route.ts)
433→    inflight.track(
434→      processObservation(payload).catch((err) => {
435→        log.error("activator.process_failed", "Failed to process observation", {
436→          observationId: payload.observation_id,
437→          error: err instanceof Error ? err.message : String(err),
438→        });
439→      }),
440→    );
441→
442→    return new Response("accepted", { status: 200 });
443→  };
444→
445→  async function processObservation(payload: ObservationWebhookPayload): Promise<void> {
446→    const { observation_id, workspace, text, severity, source_agent } = payload;
447→
448→    // Resolve target entity for dampener keying and active coverage check
449→    const target = await resolveObservationTarget(surreal, observation_id);
450→    const dampenerEntityKey = target ? `${target.table}:${target.id}` : observation_id;
451→    const dampenerEvent = buildDampenerEvent(workspace, dampenerEntityKey, source_agent);
452→    const dampenerResult = loopDampener.record(dampenerEvent);
453→
454→    if (dampenerResult.dampened) {
455→      await createDampeningMetaObservation(
456→        surreal,
457→        workspace,
458→        dampenerEntityKey,
459→        source_agent,
460→      ).catch((err) => {
461→        log.error("activator.dampening_meta_failed", "Failed to create dampening meta-observation", {
462→          workspaceId: workspace,
463→          entityId: dampenerEntityKey,
464→          error: err instanceof Error ? err.message : String(err),
465→        });
466→      });
467→      return;
468→    }
469→
470→    // Skip if target entity already has an active agent session — proxy handles it
471→    if (target) {
472→      const covered = await hasActiveCoverage(surreal, target, workspace);
473→      if (covered) {
474→        log.info("activator.skipped_active_coverage", "Skipping observation — target has active agent session", {
475→          observationId: observation_id,
476→          target: `${target.table}:${target.id}`,
477→          workspaceId: workspace,
478→        });
479→        return;
480→      }
481→    }
482→
483→    // Load registered agents for this workspace
484→    const agents = await loadWorkspaceAgents(surreal, workspace);
485→    if (agents.length === 0) {
486→      log.warn("activator.no_agents", "No agents registered with descriptions in workspace", {
487→          workspaceId: workspace,
488→          observationId: observation_id,
489→        });
490→      return;
491→    }
492→
493→    // LLM classification: which agents should handle this observation?
494→    const prompt = buildClassificationPrompt({ text, severity }, agents);
495→    const classification = await generateObject({
496→      model: classifierModel,
497→      schema: classificationSchema,
498→      prompt,
499→    });
500→
501→    const activations = classification.object.activations;
502→    log.info("activator.classified", "LLM classified agents for observation", {
503→      observationId: observation_id,
504→      agentCount: activations.length,
505→      workspaceId: workspace,
506→    });
507→
508→    // Validate agent IDs against registered agents
509→    const agentMap = new Map(agents.map((a) => [a.agentId, a]));
510→    const validActivations: Array<{ agent: RegisteredAgent; reason: string }> = [];
511→    const hallucinatedIds: string[] = [];
512→
513→    for (const activation of activations) {
514→      const agent = agentMap.get(activation.agent_id);
515→      if (!agent) {
516→        log.warn("activator.hallucinated_agent", "LLM returned unknown agent_id", {
517→          agentId: activation.agent_id,
518→          observationId: observation_id,
519→          workspaceId: workspace,
520→        });
521→        hallucinatedIds.push(activation.agent_id);
522→        continue;
523→      }
524→      validActivations.push({ agent, reason: activation.reason });
525→    }
526→
527→    // Create governance observation for hallucinated agent IDs
528→    if (hallucinatedIds.length > 0) {
529→      await createHallucinationObservation(
530→        surreal,
531→        workspace,
532→        observation_id,
533→        hallucinatedIds,
534→      ).catch((err) => {
535→        log.error("activator.hallucination_obs_failed", "Failed to create hallucination observation", {
536→          observationId: observation_id,
537→          workspaceId: workspace,
538→          error: err instanceof Error ? err.message : String(err),
539→        });
540→      });
541→    }
542→
543→    // Record the routing decision for conflict/warning observations (governance trail)
544→    if (severity === "conflict" || severity === "warning") {
545→      await createActivationDecision(
546→        surreal,
547→        workspace,
548→        observation_id,
549→        text,
550→        severity,
551→        validActivations.map((v) => ({ agentType: v.agent.agentType, reason: v.reason })),
552→      ).catch((err) => {
553→        log.error("activator.decision_failed", "Failed to create activation decision", {
554→          observationId: observation_id,
555→          workspaceId: workspace,
556→          error: err instanceof Error ? err.message : String(err),
557→        });
558→      });
559→    }
560→
561→    // Start agent sessions for matched agents
562→    for (const { agent, reason } of validActivations) {
563→      try {
564→        await createActivatedSession(surreal, {
565→          agentType: agent.agentType,
566→          workspaceId: workspace,
567→          observationId: observation_id,
568→        });
569→      } catch (err) {
570→        log.error("activator.session_failed", "Failed to create activated session", {
571→          agentType: agent.agentType,
572→          observationId: observation_id,
573→          workspaceId: workspace,
574→          error: err instanceof Error ? err.message : String(err),
575→        });
576→        continue; // skip activation callback — no DB record exists
577→      }
578→
579→      onAgentActivation({
580→        agentId: agent.agentId,
581→        agentType: agent.agentType,
582→        workspaceId: workspace,
583→        reason,
584→        observationId: observation_id,
585→        observationText: text,
586→      });
587→    }
588→  }
589→}
590→

file.content:
/**
 * Agent Activator
 *
 * POST endpoint handler called by SurrealDB DEFINE EVENT webhook when
 * observations are created. Uses LLM classification to determine which
 * registered agent types should be activated for a given observation,
 * then starts new agent sessions for matched agents.
 *
 * Observations targeting entities with active agent sessions are skipped —
 * the LLM proxy handles enriching those sessions via its own vector search.
 *
 * LLM classification over KNN because the question is "which agents can
 * ACT on this observation?" — a judgment problem, not a proximity problem.
 * See ADR-061.
 *
 * Step: 03-02 (Graph-Reactive Coordination)
 */
import { RecordId, type Surreal } from "surrealdb";
import { generateObject, type LanguageModel } from "ai";
import { z } from "zod";
import { log } from "../telemetry/logger";
import type { LoopDampener, DampenerEvent } from "./loop-dampener";

// ---------------------------------------------------------------------------
// Domain Types
// ---------------------------------------------------------------------------

/** Webhook payload from SurrealDB DEFINE EVENT on observation CREATE. */
export type ObservationWebhookPayload = {
  observation_id: string;
  workspace: string;
  text: string;
  severity: string;
  source_agent: string;
};

/** A registered agent type with its description. */
export type RegisteredAgent = {
  agentId: string;
  agentType: string;
  description: string;
};

/** An agent matched by LLM classification for activation. */
export type AgentActivation = {
  agentId: string;
  agentType: string;
  workspaceId: string;
  reason: string;
  observationId: string;
  observationText: string;
};

/** Callback invoked when the activator decides to start a new agent. */
export type OnAgentActivation = (activation: AgentActivation) => void;

/** Inflight tracker for background async work. */
export type InflightTracker = {
  track: (promise: Promise<unknown>) => void;
};

/** Dependencies injected into the agent activator. */
export type AgentActivatorDeps = {
  surreal: Surreal;
  loopDampener: LoopDampener;
  inflight: InflightTracker;
  classifierModel: LanguageModel;
  onAgentActivation: OnAgentActivation;
  /** Shared secret for webhook authentication. If undefined, all requests are allowed (dev mode). */
  internalWebhookSecret?: string;
};

// ---------------------------------------------------------------------------
// Pure Functions
// ---------------------------------------------------------------------------

/**
 * Parses and validates the webhook payload from SurrealDB DEFINE EVENT.
 * Returns undefined if the payload is invalid.
 */
export function parseWebhookPayload(
  body: unknown,
): ObservationWebhookPayload | undefined {
  if (!body || typeof body !== "object") return undefined;
  const b = body as Record<string, unknown>;

  const observation_id = b.observation_id;
  const workspace = b.workspace;
  const text = b.text;
  const severity = b.severity;
  const source_agent = b.source_agent;

  if (
    typeof observation_id !== "string" ||
    typeof text !== "string" ||
    typeof severity !== "string" ||
    typeof source_agent !== "string" ||
    !workspace
  ) {
    return undefined;
  }

  // workspace may be a string "workspace:id" or just the id
  let workspaceId: string;
  if (typeof workspace === "string") {
    workspaceId = workspace.includes(":") ? workspace.split(":").slice(1).join(":") : workspace;
  } else if (workspace instanceof RecordId) {
    workspaceId = workspace.id as string;
  } else {
    return undefined;
  }

  return {
    observation_id: typeof observation_id === "string" && observation_id.includes(":")
      ? observation_id.split(":").slice(1).join(":")
      : observation_id,
    workspace: workspaceId,
    text,
    severity,
    source_agent,
  };
}

/**
 * Validates the webhook request's Authorization header against the shared secret.
 * Returns true if the secret is not configured (dev mode) or if the header matches.
 */
export function validateWebhookSecret(
  authHeader: string | undefined,
  secret: string | undefined,
): boolean {
  if (!secret) return true; // dev mode: no secret configured, allow all
  if (!authHeader) return false;
  return authHeader === `Bearer ${secret}`;
}

/**
 * Builds a dampener event key from webhook payload fields.
 */
export function buildDampenerEvent(
  workspaceId: string,
  entityId: string,
  sourceAgent: string,
): DampenerEvent {
  return { workspaceId, entityId, sourceAgent };
}

/**
 * Builds the LLM classification prompt from observation + agent descriptions.
 */
export function buildClassificationPrompt(
  observation: { text: string; severity: string },
  agents: ReadonlyArray<RegisteredAgent>,
): string {
  const agentList = agents
    .map((a) => `- Agent "${a.agentId}" (type: ${a.agentType}): ${a.description}`)
    .join("\n");

  return `You are an agent activator. Given an observation from a knowledge graph, determine which registered agents should be started to handle it.

## Observation
Severity: ${observation.severity}
Text: ${observation.text}

## Registered Agents
${agentList}

## Instructions
- Select agents that can TAKE ACTION on this observation (not just agents with related keywords)
- Consider the severity: conflict observations need immediate action, info observations may not need any agent
- If no agent is relevant, return an empty list
- For each selected agent, explain briefly why it should be activated`;
}

// ---------------------------------------------------------------------------
// LLM Classification Schema
// ---------------------------------------------------------------------------

const classificationSchema = z.object({
  activations: z.array(z.object({
    agent_id: z.string().describe("The agent ID to activate"),
    reason: z.string().describe("Brief explanation of why this agent should handle the observation"),
  })),
});

// ---------------------------------------------------------------------------
// DB Queries (Side-Effect Boundary)
// ---------------------------------------------------------------------------

/**
 * Loads all registered agents for a workspace (via identity membership).
 */
async function loadWorkspaceAgents(
  surreal: Surreal,
  workspaceId: string,
): Promise<RegisteredAgent[]> {
  const workspaceRecord = new RecordId("workspace", workspaceId);

  // Two-step: get workspace member identities, then find their agents
  const result = await surreal.query<[unknown, Array<{
    id: RecordId;
    agent_type: string;
    description: string;
  }>]>(
    `LET $members = (SELECT VALUE in FROM member_of WHERE out = $ws);
     SELECT id, agent_type, description FROM agent
     WHERE managed_by IN $members
     AND description IS NOT NONE;`,
    { ws: workspaceRecord },
  );

  return (result[1] ?? []).map((a) => ({
    agentId: a.id.id as string,
    agentType: a.agent_type,
    description: a.description,
  }));
}

/**
 * Resolves the target entity for an observation by querying the observes edge.
 */
async function resolveObservationTarget(
  surreal: Surreal,
  observationId: string,
): Promise<{ table: string; id: string } | undefined> {
  const obsRecord = new RecordId("observation", observationId);
  const result = await surreal.query<[Array<{ out: RecordId }>]>(
    `SELECT out FROM observes WHERE in = $obs LIMIT 1;`,
    { obs: obsRecord },
  );
  const edge = result[0]?.[0];
  if (edge?.out instanceof RecordId) {
    return { table: edge.out.table.name, id: edge.out.id as string };
  }
  return undefined;
}

/**
 * Checks whether the observation's target entity already has an active
 * agent session. If so, the proxy handles context enrichment.
 */
async function hasActiveCoverage(
  surreal: Surreal,
  target: { table: string; id: string },
  workspaceId: string,
): Promise<boolean> {
  const workspaceRecord = new RecordId("workspace", workspaceId);
  const taskRecord = new RecordId(target.table, target.id);

  const result = await surreal.query<[Array<{ count: number }>]>(
    `SELECT count() AS count FROM agent_session
     WHERE task_id = $task AND workspace = $ws AND orchestrator_status = "active"
     LIMIT 1;`,
    { task: taskRecord, ws: workspaceRecord },
  );

  const count = result[0]?.[0]?.count ?? 0;
  return count > 0;
}

/**
 * Creates a new agent session for a matched agent, marking it as "spawning".
 */
async function createActivatedSession(
  surreal: Surreal,
  match: { agentType: string; workspaceId: string; observationId: string },
): Promise<string> {
  const sessionId = `sess-${crypto.randomUUID()}`;
  const sessionRecord = new RecordId("agent_session", sessionId);
  const workspaceRecord = new RecordId("workspace", match.workspaceId);
  const observationRecord = new RecordId("observation", match.observationId);

  await surreal.query(`CREATE $sess CONTENT $content;`, {
    sess: sessionRecord,
    content: {
      agent: match.agentType,
      started_at: new Date(),
      workspace: workspaceRecord,
      orchestrator_status: "spawning",
      source: "activator",
      triggered_by: observationRecord,
      created_at: new Date(),
    },
  });

  return sessionId;
}

/**
 * Creates a provisional decision recording the activator's routing choice.
 * Only for conflict/warning severity observations. Links to the observation
 * via relates_to edge. Appears in the governance feed for human oversight.
 */
async function createActivationDecision(
  surreal: Surreal,
  workspaceId: string,
  observationId: string,
  observationText: string,
  severity: string,
  activatedAgents: Array<{ agentType: string; reason: string }>,
): Promise<string> {
  const decisionId = `dec-act-${crypto.randomUUID()}`;
  const decisionRecord = new RecordId("decision", decisionId);
  const workspaceRecord = new RecordId("workspace", workspaceId);
  const observationRecord = new RecordId("observation", observationId);

  const agentSummary = activatedAgents.length > 0
    ? activatedAgents.map((a) => `${a.agentType}: ${a.reason}`).join("; ")
    : "No agents matched — observation logged for future context";

  const summary = activatedAgents.length > 0
    ? `Activated ${activatedAgents.length} agent(s) for ${severity} observation`
    : `No agents activated for ${severity} observation`;

  await surreal.query(`CREATE $dec CONTENT $content;`, {
    dec: decisionRecord,
    content: {
      summary,
      rationale: `Observation: "${observationText}"\n\nRouting: ${agentSummary}`,
      status: "provisional",
      inferred_by: "agent_activator",
      category: "operations",
      workspace: workspaceRecord,
      based_on: [observationRecord],
      created_at: new Date(),
      updated_at: new Date(),
    },
  });

  // Link decision to observation
  await surreal.query(
    `RELATE $dec->relates_to->$obs SET created_at = time::now();`,
    { dec: decisionRecord, obs: observationRecord },
  );

  return decisionId;
}

/**
 * Creates a governance observation when the LLM hallucinates unknown agent IDs.
 * Makes the hallucination visible in the feed for human oversight.
 */
async function createHallucinationObservation(
  surreal: Surreal,
  workspaceId: string,
  observationId: string,
  hallucinatedIds: string[],
): Promise<void> {
  const metaId = `meta-halluc-${crypto.randomUUID()}`;
  const metaRecord = new RecordId("observation", metaId);
  const workspaceRecord = new RecordId("workspace", workspaceId);
  const sourceObsRecord = new RecordId("observation", observationId);

  await surreal.query(`CREATE $obs CONTENT $content;`, {
    obs: metaRecord,
    content: {
      text: `Agent activator LLM hallucinated ${hallucinatedIds.length} agent ID(s) for observation ${observationId}: ${hallucinatedIds.join(", ")}`,
      severity: "info",
      status: "open",
      category: "engineering",
      source_agent: "agent_activator",
      workspace: workspaceRecord,
      created_at: new Date(),
      updated_at: new Date(),
    },
  });

  // Link to the source observation
  await surreal.query(
    `RELATE $meta->observes->$obs SET created_at = time::now();`,
    { meta: metaRecord, obs: sourceObsRecord },
  );
}

/**
 * Creates a meta-observation when the loop dampener activates.
 */
async function createDampeningMetaObservation(
  surreal: Surreal,
  workspaceId: string,
  entityId: string,
  sourceAgent: string,
): Promise<void> {
  const metaId = `meta-${crypto.randomUUID()}`;
  const metaRecord = new RecordId("observation", metaId);
  const workspaceRecord = new RecordId("workspace", workspaceId);

  await surreal.query(`CREATE $obs CONTENT $content;`, {
    obs: metaRecord,
    content: {
      text: `Loop dampener activated: rapid-fire observations from ${sourceAgent} targeting ${entityId} have been dampened to prevent cascading agent invocations`,
      severity: "info",
      status: "open",
      category: "engineering",
      source_agent: "agent_activator",
      workspace: workspaceRecord,
      created_at: new Date(),
      updated_at: new Date(),
    },
  });
}

// ---------------------------------------------------------------------------
// Agent Activator Handler (Side-Effect Shell)
// ---------------------------------------------------------------------------

/**
 * Creates the agent activator POST endpoint handler.
 *
 * Called by SurrealDB DEFINE EVENT webhook on observation CREATE.
 * Parses the webhook payload, checks loop dampener, checks active coverage,
 * uses LLM to classify which agents should handle the observation,
 * starts new agent sessions for matched agents.
 */
export function createAgentActivatorHandler(deps: AgentActivatorDeps) {
  const { surreal, loopDampener, inflight, classifierModel, onAgentActivation, internalWebhookSecret } = deps;

  return async function handleObservationWebhook(request: Request): Promise<Response> {
    // Validate shared secret if configured
    const authHeader = request.headers.get("authorization") ?? undefined;
    if (!validateWebhookSecret(authHeader, internalWebhookSecret)) {
      return new Response("unauthorized", { status: 401 });
    }

    const body = await request.json().catch(() => undefined);
    const payload = parseWebhookPayload(body);

    if (!payload) {
      return new Response("invalid payload", { status: 200 });
    }

    // Process async — return 200 immediately (same pattern as observer-route.ts)
    inflight.track(
      processObservation(payload).catch((err) => {
        log.error("activator.process_failed", "Failed to process observation", {
          observationId: payload.observation_id,
          error: err instanceof Error ? err.message : String(err),
        });
      }),
    );

    return new Response("accepted", { status: 200 });
  };

  async function processObservation(payload: ObservationWebhookPayload): Promise<void> {
    const { observation_id, workspace, text, severity, source_agent } = payload;

    // Resolve target entity for dampener keying and active coverage check
    const target = await resolveObservationTarget(surreal, observation_id);
    const dampenerEntityKey = target ? `${target.table}:${target.id}` : observation_id;
    const dampenerEvent = buildDampenerEvent(workspace, dampenerEntityKey, source_agent);
    const dampenerResult = loopDampener.record(dampenerEvent);

    if (dampenerResult.dampened) {
      await createDampeningMetaObservation(
        surreal,
        workspace,
        dampenerEntityKey,
        source_agent,
      ).catch((err) => {
        log.error("activator.dampening_meta_failed", "Failed to create dampening meta-observation", {
          workspaceId: workspace,
          entityId: dampenerEntityKey,
          error: err instanceof Error ? err.message : String(err),
        });
      });
      return;
    }

    // Skip if target entity already has an active agent session — proxy handles it
    if (target) {
      const covered = await hasActiveCoverage(surreal, target, workspace);
      if (covered) {
        log.info("activator.skipped_active_coverage", "Skipping observation — target has active agent session", {
          observationId: observation_id,
          target: `${target.table}:${target.id}`,
          workspaceId: workspace,
        });
        return;
      }
    }

    // Load registered agents for this workspace
    const agents = await loadWorkspaceAgents(surreal, workspace);
    if (agents.length === 0) {
      log.warn("activator.no_agents", "No agents registered with descriptions in workspace", {
          workspaceId: workspace,
          observationId: observation_id,
        });
      return;
    }

    // LLM classification: which agents should handle this observation?
    const prompt = buildClassificationPrompt({ text, severity }, agents);
    const classification = await generateObject({
      model: classifierModel,
      schema: classificationSchema,
      prompt,
    });

    const activations = classification.object.activations;
    log.info("activator.classified", "LLM classified agents for observation", {
      observationId: observation_id,
      agentCount: activations.length,
      workspaceId: workspace,
    });

    // Validate agent IDs against registered agents
    const agentMap = new Map(agents.map((a) => [a.agentId, a]));
    const validActivations: Array<{ agent: RegisteredAgent; reason: string }> = [];
    const hallucinatedIds: string[] = [];

    for (const activation of activations) {
      const agent = agentMap.get(activation.agent_id);
      if (!agent) {
        log.warn("activator.hallucinated_agent", "LLM returned unknown agent_id", {
          agentId: activation.agent_id,
          observationId: observation_id,
          workspaceId: workspace,
        });
        hallucinatedIds.push(activation.agent_id);
        continue;
      }
      validActivations.push({ agent, reason: activation.reason });
    }

    // Create governance observation for hallucinated agent IDs
    if (hallucinatedIds.length > 0) {
      await createHallucinationObservation(
        surreal,
        workspace,
        observation_id,
        hallucinatedIds,
      ).catch((err) => {
        log.error("activator.hallucination_obs_failed", "Failed to create hallucination observation", {
          observationId: observation_id,
          workspaceId: workspace,
          error: err instanceof Error ? err.message : String(err),
        });
      });
    }

    // Record the routing decision for conflict/warning observations (governance trail)
    if (severity === "conflict" || severity === "warning") {
      await createActivationDecision(
        surreal,
        workspace,
        observation_id,
        text,
        severity,
        validActivations.map((v) => ({ agentType: v.agent.agentType, reason: v.reason })),
      ).catch((err) => {
        log.error("activator.decision_failed", "Failed to create activation decision", {
          observationId: observation_id,
          workspaceId: workspace,
          error: err instanceof Error ? err.message : String(err),
        });
      });
    }

    // Start agent sessions for matched agents
    for (const { agent, reason } of validActivations) {
      try {
        await createActivatedSession(surreal, {
          agentType: agent.agentType,
          workspaceId: workspace,
          observationId: observation_id,
        });
      } catch (err) {
        log.error("activator.session_failed", "Failed to create activated session", {
          agentType: agent.agentType,
          observationId: observation_id,
          workspaceId: workspace,
          error: err instanceof Error ? err.message : String(err),
        });
        continue; // skip activation callback — no DB record exists
      }

      onAgentActivation({
        agentId: agent.agentId,
        agentType: agent.agentType,
        workspaceId: workspace,
        reason,
        observationId: observation_id,
        observationText: text,
      });
    }
  }
}

