  1→/**
  2→ * Feed SSE Bridge
  3→ *
  4→ * Transforms graph events from the Live Select Manager into GovernanceFeedItem-
  5→ * shaped SSE events, assigns governance tiers via simple rules, batches within
  6→ * a configurable window (default 500ms), and pushes via the SSE Registry.
  7→ *
  8→ * Pure core: transformToFeedItem, assignTier, classifyTierTransition are pure.
  9→ * Effects at boundary: createFeedSseBridge wires IO (onEvent, emitWorkspaceEvent).
 10→ *
 11→ * Step: 01-04 (Graph-Reactive Coordination)
 12→ */
 13→import { RecordId } from "surrealdb";
 14→import type { GovernanceTier } from "../../shared/contracts";
 15→import type { LiveSelectEvent } from "./live-select-manager";
 16→import type { WorkspaceStreamEvent, SseRegistry } from "../streaming/sse-registry";
 17→import type { LiveSelectManager } from "./live-select-manager";
 18→
 19→// ---------------------------------------------------------------------------
 20→// Domain Types
 21→// ---------------------------------------------------------------------------
 22→
 23→/** A feed item produced by the bridge, matching the WorkspaceStreamEvent item shape. */
 24→export type FeedBridgeItem = {
 25→  id: string;
 26→  tier: GovernanceTier;
 27→  entityId: string;
 28→  entityKind: string;
 29→  entityName: string;
 30→  reason: string;
 31→  status: string;
 32→  severity?: string;
 33→  createdAt: string;
 34→};
 35→
 36→type TierTransitionResult = {
 37→  previousTier: GovernanceTier;
 38→  newTier: GovernanceTier;
 39→  isTransition: boolean;
 40→};
 41→
 42→// ---------------------------------------------------------------------------
 43→// Pure Functions: Transform
 44→// ---------------------------------------------------------------------------
 45→
 46→/**
 47→ * Extracts the display name from a LiveSelectEvent value based on the table.
 48→ * Each entity type stores its name in a different field.
 49→ */
 50→function extractEntityName(table: string, value: Record<string, unknown>): string {
 51→  switch (table) {
 52→    case "decision":
 53→      return (value.summary as string) ?? "Unnamed decision";
 54→    case "task":
 55→      return (value.title as string) ?? "Unnamed task";
 56→    case "observation":
 57→      return (value.text as string) ?? "Unnamed observation";
 58→    case "question":
 59→      return (value.text as string) ?? "Unnamed question";
 60→    case "suggestion":
 61→      return (value.text as string) ?? "Unnamed suggestion";
 62→    case "learning":
 63→      return (value.text as string) ?? "Unnamed learning";
 64→    case "agent_session":
 65→      return (value.task_title as string) ?? `Agent session`;
 66→    default:
 67→      return `Unknown ${table}`;
 68→  }
 69→}
 70→
 71→/**
 72→ * Builds the human-readable reason string for a feed item.
 73→ */
 74→function buildReason(table: string, status: string, severity?: string): string {
 75→  switch (table) {
 76→    case "decision":
 77→      if (["provisional", "proposed", "extracted"].includes(status)) {
 78→        return `${capitalize(status)} decision awaiting confirmation`;
 79→      }
 80→      return `Decision ${status}`;
 81→    case "task":
 82→      if (status === "blocked") return "Task is blocked";
 83→      if (status === "done" || status === "completed") return `Recently completed task`;
 84→      return `Task ${status}`;
 85→    case "observation":
 86→      return `${capitalize(severity ?? "info")} observation`;
 87→    case "question":
 88→      return `Open question`;
 89→    case "suggestion":
 90→      return `Pending suggestion`;
 91→    case "learning":
 92→      if (status === "pending_approval") return `Pending learning awaiting approval`;
 93→      return `Learning ${status}`;
 94→    case "agent_session":
 95→      return `Agent session ${status}`;
 96→    default:
 97→      return `${table} ${status}`;
 98→  }
 99→}
100→
101→/**
102→ * Transforms a LiveSelectEvent into a FeedBridgeItem.
103→ * Returns undefined for DELETE events (handled as removals separately).
104→ */
105→export function transformToFeedItem(event: LiveSelectEvent): FeedBridgeItem | undefined {
106→  if (event.action === "DELETE") return undefined;
107→
108→  const { table, recordId, value } = event;
109→  const status = (value.status as string) ?? "unknown";
110→  const severity = value.severity as string | undefined;
111→  const entityName = extractEntityName(table, value);
112→  const tier = assignTier(table, status, severity);
113→  const createdAt = toIsoSafe(value.created_at) ?? new Date().toISOString();
114→
115→  return {
116→    id: buildFeedItemId(recordId),
117→    tier,
118→    entityId: recordId,
119→    entityKind: table,
120→    entityName,
121→    reason: buildReason(table, status, severity),
122→    status,
123→    ...(severity ? { severity } : {}),
124→    createdAt,
125→  };
126→}
127→
128→// ---------------------------------------------------------------------------
129→// Pure Functions: Tier Assignment
130→// ---------------------------------------------------------------------------
131→
132→/**
133→ * Assigns a governance tier based on entity type, status, and severity.
134→ *
135→ * Rules:
136→ * - blocking: provisional/proposed/extracted decisions, open questions
137→ * - review: warning/conflict observations (open/acknowledged), blocked tasks,
138→ *           pending learnings, pending suggestions
139→ * - awareness: everything else
140→ */
141→export function assignTier(
142→  table: string,
143→  status: string,
144→  severity: string | undefined,
145→): GovernanceTier {
146→  // Blocking tier
147→  if (table === "decision" && ["provisional", "proposed", "extracted"].includes(status)) {
148→    return "blocking";
149→  }
150→  if (table === "question" && status === "open") {
151→    return "blocking";
152→  }
153→
154→  // Review tier
155→  if (table === "observation" && ["open", "acknowledged"].includes(status)) {
156→    if (severity === "warning" || severity === "conflict") {
157→      return "review";
158→    }
159→  }
160→  if (table === "task" && status === "blocked") {
161→    return "review";
162→  }
163→  if (table === "learning" && status === "pending_approval") {
164→    return "review";
165→  }
166→  if (table === "suggestion" && status === "pending") {
167→    return "review";
168→  }
169→
170→  // Everything else
171→  return "awareness";
172→}
173→
174→// ---------------------------------------------------------------------------
175→// Pure Functions: Tier Transition Detection
176→// ---------------------------------------------------------------------------
177→
178→/**
179→ * Classifies whether a status change causes a tier transition.
180→ * Used to generate removal IDs for items that moved between tiers.
181→ */
182→export function classifyTierTransition(
183→  table: string,
184→  previousStatus: string,
185→  newStatus: string,
186→): TierTransitionResult {
187→  const previousTier = assignTier(table, previousStatus, undefined);
188→  const newTier = assignTier(table, newStatus, undefined);
189→
190→  return {
191→    previousTier,
192→    newTier,
193→    isTransition: previousTier !== newTier,
194→  };
195→}
196→
197→// ---------------------------------------------------------------------------
198→// Pure Functions: Event ID Counter
199→// ---------------------------------------------------------------------------
200→
201→/**
202→ * Creates a monotonically increasing event ID counter for SSE reconnection
203→ * delta sync support.
204→ */
205→export function createEventIdCounter(startFrom: number = 0): () => number {
206→  let counter = startFrom;
207→  return () => ++counter;
208→}
209→
210→// ---------------------------------------------------------------------------
211→// Batching
212→// ---------------------------------------------------------------------------
213→
214→type BatcherConfig = {
215→  windowMs: number;
216→  onFlush: (items: FeedBridgeItem[], removals: string[]) => void;
217→};
218→
219→type Batcher = {
220→  add: (item: FeedBridgeItem, removalId?: string) => void;
221→  addRemoval: (removalId: string) => void;
222→  dispose: () => void;
223→};
224→
225→/**
226→ * Creates a batcher that collects feed items within a time window
227→ * and flushes them as a single batch when the window expires.
228→ *
229→ * This prevents client flooding when many graph changes happen
230→ * in rapid succession (e.g., bulk extraction).
231→ */
232→export function createBatcher(config: BatcherConfig): Batcher {
233→  let pendingItems: FeedBridgeItem[] = [];
234→  let pendingRemovals: string[] = [];
235→  let timerId: ReturnType<typeof setTimeout> | undefined;
236→  let disposed = false;
237→
238→  function flush(): void {
239→    if (disposed) return;
240→    if (pendingItems.length === 0 && pendingRemovals.length === 0) return;
241→
242→    const items = pendingItems;
243→    const removals = pendingRemovals;
244→    pendingItems = [];
245→    pendingRemovals = [];
246→    timerId = undefined;
247→
248→    config.onFlush(items, removals);
249→  }
250→
251→  function add(item: FeedBridgeItem, removalId?: string): void {
252→    if (disposed) return;
253→
254→    pendingItems.push(item);
255→    if (removalId) {
256→      pendingRemovals.push(removalId);
257→    }
258→
259→    if (timerId === undefined) {
260→      timerId = setTimeout(flush, config.windowMs);
261→    }
262→  }
263→
264→  function addRemoval(removalId: string): void {
265→    if (disposed) return;
266→    pendingRemovals.push(removalId);
267→    if (timerId === undefined) {
268→      timerId = setTimeout(flush, config.windowMs);
269→    }
270→  }
271→
272→  function dispose(): void {
273→    disposed = true;
274→    if (timerId !== undefined) {
275→      clearTimeout(timerId);
276→      timerId = undefined;
277→    }
278→    pendingItems = [];
279→    pendingRemovals = [];
280→  }
281→
282→  return { add, addRemoval, dispose };
283→}
284→
285→// ---------------------------------------------------------------------------
286→// Internal Helpers
287→// ---------------------------------------------------------------------------
288→
289→function buildFeedItemId(recordId: string): string {
290→  return recordId;
291→}
292→
293→function capitalize(value: string): string {
294→  if (value.length === 0) return value;
295→  return value.charAt(0).toUpperCase() + value.slice(1);
296→}
297→
298→function toIsoSafe(value: unknown): string | undefined {
299→  if (!value) return undefined;
300→  if (value instanceof Date) return value.toISOString();
301→  if (typeof value === "string") {
302→    try {
303→      return new Date(value).toISOString();
304→    } catch {
305→      return undefined;
306→    }
307→  }
308→  return undefined;
309→}
310→
311→// ---------------------------------------------------------------------------
312→// Bridge Wiring (Side-Effect Shell)
313→// ---------------------------------------------------------------------------
314→
315→export type FeedSseBridgeDeps = {
316→  liveSelectManager: LiveSelectManager;
317→  sseRegistry: SseRegistry;
318→  batchWindowMs?: number;
319→};
320→
321→export type FeedSseBridge = {
322→  /** Start listening for events on the given workspace. Returns unsubscribe function. */
323→  subscribe: (workspaceId: string) => () => void;
324→  /** Subscribe to all workspaces (global consumer). Returns unsubscribe function. */
325→  subscribeAll: () => () => void;
326→};
327→
328→/**
329→ * Creates the Feed SSE Bridge that connects the Live Select Manager
330→ * to the SSE Registry, transforming graph events into feed updates.
331→ *
332→ * Dependency injection: all IO passed as function parameters.
333→ */
334→export function createFeedSseBridge(deps: FeedSseBridgeDeps): FeedSseBridge {
335→  const { liveSelectManager, sseRegistry } = deps;
336→  const batchWindowMs = deps.batchWindowMs ?? 500;
337→  const batchers = new Map<string, Batcher>();
338→
339→  function getOrCreateBatcher(workspaceId: string): Batcher {
340→    let batcher = batchers.get(workspaceId);
341→    if (!batcher) {
342→      batcher = createBatcher({
343→        windowMs: batchWindowMs,
344→        onFlush: (items, removals) => {
345→          const event: WorkspaceStreamEvent = {
